def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    import difflib

    orig = Presentation(original_ppt_path)
    mod = Presentation(modified_ppt_path)
    orig_slide = orig.slides[4]
    mod_slide = mod.slides[4]

    def get_bullets(slide):
        bullets = []
        for shape in slide.shapes:
            if not shape.has_text_frame:
                continue
            for paragraph in shape.text_frame.paragraphs:
                if paragraph.level > 0 or (paragraph.text.strip() and paragraph.text.strip()[0] in '•-–'):
                    bullets.append(paragraph.text.strip())
        return bullets

    orig_bullets = set(get_bullets(orig_slide))
    mod_bullets = set(get_bullets(mod_slide))
    new_bullets = mod_bullets - orig_bullets

    for new_bullet in new_bullets:
        for bullet in orig_bullets:
            if difflib.SequenceMatcher(None, new_bullet.lower(), bullet.lower()).ratio() > 0.9:
                return (f"Bullet point '{new_bullet}' is a duplicate of '{bullet}'.", 0.0)
    return ("New bullet point is not a duplicate.", 1.0)

